import mongoose from 'mongoose';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });
dotenv.config({ path: path.resolve(__dirname, '../.env') });

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) { console.error('MONGO_URI not found'); process.exit(1); }

const examCategorySchema = new mongoose.Schema({
  name: { type: String, required: true, trim: true },
  type: { type: String, enum: ['Central', 'State'], required: true },
  description: { type: String, trim: true }
}, { timestamps: true });

const examSchema = new mongoose.Schema({
  category: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamCategory', required: true },
  name: { type: String, required: true, trim: true },
  code: { type: String, required: true, uppercase: true, trim: true },
  description: { type: String, trim: true },
  isActive: { type: Boolean, default: true },
  logo: { type: String }
}, { timestamps: true });

const examPatternSchema = new mongoose.Schema({
  exam: { type: mongoose.Schema.Types.ObjectId, ref: 'Exam', required: true },
  title: { type: String, required: true, trim: true },
  duration: { type: Number, required: true, min: 1 },
  totalMarks: { type: Number, required: true, min: 0 },
  negativeMarking: { type: Number, default: 0, min: 0 },
  sections: [{
    name: { type: String, required: true, trim: true },
    totalQuestions: { type: Number, required: true, min: 1 },
    marksPerQuestion: { type: Number, required: true, min: 0 },
    negativePerQuestion: { type: Number, default: 0, min: 0 },
    sectionDuration: { type: Number, min: 0 }
  }]
}, { timestamps: true });

const practiceTestSchema = new mongoose.Schema({
  examPattern: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamPattern', required: true },
  title: { type: String, required: true, trim: true },
  slug: { type: String, lowercase: true, trim: true },
  totalMarks: { type: Number, required: true, min: 0 },
  duration: { type: Number, required: true, min: 1 },
  accessLevel: { type: String, enum: ['FREE', 'PRO'], default: 'FREE' },
  isPYQ: { type: Boolean, default: false },
  pyqYear: { type: Number, default: null },
  pyqShift: { type: String, default: null, trim: true },
  pyqExamName: { type: String, default: null, trim: true },
  publishedAt: { type: Date, default: Date.now },
  questions: [{
    questionText: { type: String, required: true },
    questionImage: { type: String, default: '' },
    options: [{ type: String, required: true }],
    optionImages: [{ type: String, default: '' }],
    correctAnswerIndex: { type: Number, required: true, min: 0 },
    explanation: { type: String, trim: true },
    section: { type: String, required: true, trim: true },
    tags: [{ type: String, trim: true }],
    difficulty: { type: String, enum: ['easy', 'medium', 'hard', 'mixed'], default: 'medium' }
  }]
}, { timestamps: true });

const ExamCategory = mongoose.models.ExamCategory || mongoose.model('ExamCategory', examCategorySchema);
const Exam = mongoose.models.Exam || mongoose.model('Exam', examSchema);
const ExamPattern = mongoose.models.ExamPattern || mongoose.model('ExamPattern', examPatternSchema);
const PracticeTest = mongoose.models.PracticeTest || mongoose.model('PracticeTest', practiceTestSchema);

const REA = 'General Intelligence';
const ENG = 'English Language';
const QA  = 'Quantitative Aptitude';
const GA  = 'General Awareness';

const KEY = [2, 1, 1, 3, 1, 1, 1, 2, 2, 3, 1, 1, 1, 4, 1, 1, 2, 4, 3, 2, 1, 1, 4, 3, 4, 1, 2, 3, 3, 2, 3, 2, 3, 1, 2, 3, 1, 2, 1, 2, 2, 1, 2, 1, 1, 3, 3, 2, 3, 2, 1, 1, 3, 2, 1, 1, 2, 2, 2, 1, 3, 2, 1, 1, 2, 1, 1, 1, 2, 1, 2, 2, 2, 3, 2, 2, 1, 1, 1, 3, 2, 3, 4, 1, 4, 2, 2, 3, 2, 3, 3, 2, 2, 4, 2, 1, 3, 2, 1, 1];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `Statements: 1. All engineers are problem-solvers. 2. Some problem-solvers are creative. 3. No creative person is careless. Conclusions: I. Some engineers are creative. II. Some problem-solvers are not careless.`, o: [`Only I follows`, `Only II follows`, `Both I and II follow`, `Neither I nor II follows`], e: `I is not necessarily true (engineers and creative may be disjoint). II is true (some problem-solvers are creative, and no creative is careless, so those problem-solvers are not careless). Only II. Option B.` },
  { s: `General Intelligence`, q: `In a numbering sysSteimmi,la5r-digit codes are formed where the first digit cannot be zero. What is the maximum number of such unique codes possible? Paper (Held`, o: [`90,000`, `99,999`, `1,00,000`, `89,999`], e: `Given: In a numbering system, 5-digit codes are formed where the first digit cannot be zero. Solution: A 5-digit code means digits from 00000 to 99999 But the first digit cannot be zero, so it must be 1­9 9 choices The remaining 4 digits can be 0­9 10 choices each Total number of codes = 9 × 10 × 10 × 10 × 10 = 90,000 So, 90,000 is the maximum number of such unique codes possible. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Assuming the statements given below are true, which of the following conclusions can be logically deduced? Statement: The company has introduced flexible working hours for its employees. Conclusions: I. Employees can choose their working time. II. The company aims to improve work-life balance.`, o: [`Only I follows`, `Only II follows`, `Both I and II follow`, `Neither I nor II follows`], e: `Statement: The company has introduced flexible working hours for its employees. Conclusions: I. Employees can choose their working time. This logically follows, because flexible working hours imply some choice in when employees work. II. The company aims to improve work-life balance. This is a possible intention, but it is not directly stated or guaranteed by the statement. So, Only I follows. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Find the appropriate word that can replace the question mark (?) and logically complete the sequence: Pager, Mobile, Smartphone, ?`, o: [`Tablet`, `Laptop`, `Smartwatch`, `Desktop`], e: `Given: Pager, Mobile, Smartphone, ? Logic: Devices show technological evolution toward more compact, wearable personal communication. Pager basic one-way communication Mobile two-way calling Smartphone advanced, multi-functional communication Smartwatch next step: more compact and wearable smart communication device So, smartwatch is missing term. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `The ratio of present ages of X and Y is 5 : 6. After 4 years, the ratio will be 6 : 7. What is X's present age?`, o: [`20 years`, `24 years`, `30 years`, `36 years`], e: `Given: The ratio of present ages of X and Y is 5 : 6. After 4 years, the ratio will be 6 : 7. Solution: Let the present ages of X and Y be 5k and 6k respectively. After 4 years: X's age = (5k + 4) Y's age = (6k + 4) Given ratio after 4 years: 5k + 4 6 = 6k + 4 7 Cross-multiply: 7(5k + 4) = 6(6k + 4) 35k + 28 = 36k + 24 k=4 So, X's present age: 5k = 5 × 4 = 20 years So, 20 years is X's present age. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Some mathematical operations are given below. Choose the expression which is mathematically correct. If X = 12, Y = 18, and Z = 24, what is the value of ((X + Y) × Z) mod 10?`, o: [`0`, `2`, `6`, `8`], e: `Given: If X = 12, Y = 18, and Z = 24, what is the value of ((X + Y) × Z) mod 10? Using BODMAS rule. Symbol [], , () Operation preference wise Brackets (power), (root), of Orders, of Division ÷ Multiplication × Addition + Subtraction - New equation: ((12 + 18) × 24) mod 10 = ? (30 × 24) mod 10 = ? 720 mod 10 = 0 Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Instruction: Identify the assumptions that must hold for the statement to be valid and choose the correct option. Statement: Excessive use of social media among teenagers leads to reduced physical activity, increased stress levels, and negatively affects mental health. Assumptions: I. Social media usage influences the lifestyle and habits of teenagers. II. Reduced physical activity has no impact on mental health. III. Increased screen time can contribute to stress and mental health issues.`, o: [`Only I and III are implicit`, `Only II and III are implicit`, `Only I is implicit`, `All assumptions are implicit`], e: `Statement: Excessive use of social media among teenagers leads to reduced physical activity, increased stress levels, and negatively affects mental health. Assumptions: I. Social media usage influences the lifestyle and habits of teenagers. This is necessary for the statement to hold true. Without this influence, the effects mentioned would not occur. II. Reduced physical activity has no impact on mental health. This contradicts the statement, which suggests negative effects on mental health. Hence, it is not implicit. III. Increased screen time can contribute to stress and mental health issues. This directly supports the statement and must be assumed to be true. So, Only I and III are implicit. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In this question, some conditions are given. You have to make a logical judgment. 1. All birds have wings. 2. No mammals have wings. Which of the following must be true?`, o: [`All winged animals are birds`, `No birds are mammals`, `Some birds are mammals`, `All mammals are flightless`], e: `Given: 1. All birds have wings. 2. No mammals have wings. From the given statements possible Venn diagram will be. We check options: Option (a): All winged animals are birds. (False) O ption (b): No birds are mammals. (True, this must be true based on the statements). Option (c): Some birds are mammals. (False) Option (d): All mammals are flightless. (False, there is no information about flightless). So, no birds are mammals must be true. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Which number does NOT belong to the sequence? 4, 10, 15, 28, 40, 54`, o: [`10`, `15`, `28`, `40`], e: `Given: 4, 10, 15, 28, 40, 54 Logic: Numbers are increasing even number from 6. 4 + 6 = 10 10 + 8 =15 18 + 10 = 28 28 + 12 = 40 40 + 14 = 54 So, the wrong term is 15. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Some social situations are given below. Choose the most appropriate course of action. You are leading a team where one member has recently become less communicative and avoids group discussions, though their work output is satisfactory. Other team members feel coordination is suffering.`, o: [`Issue a formal warning about communication gaps`, `Redistribute their tasks to other team members`, `Have a private, supportive conversation to understand concerns and offer help`, `Ignore the issue since work quality is unaffected`], e: `Given: You are leading a team where one member has recently become less communicative and avoids group discussions, though their work output is satisfactory. Other team members feel coordination is suffering. Explanation: The right thing to do is to talk to the team member privately. This helps you understand why they have become less communicative and shows support, while also finding ways to improve coordination. Giving a warning, shifting their work to others, or ignoring the issue can create bigger problems later. So, H ave a private, supportive conversation to understand concerns and offer help. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `In the following question, select the related word from the given alternatives: Judge : Court :: Doctor : ?`, o: [`Hospital`, `Medicine`, `Patient`, `Nurse`], e: `Given: Judge : Court :: Doctor : ? A Judge works in a Court. Similarly, Doctor : ? A Doctor works in a Hospital. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In this question, four sets of name and address are given, out of which two are exactly same. Find those two combinations. 1. Bhopal Head Office Bhopal GPO Campus - 462001 2. Bhopal Head Office Bhopal GPO Campus - 462001 3. Bhopal Head Office Bhopal PPO Campus - 462001 4. Bhopal Head Office Bhopal GPO Campas - 462001`, o: [`1 and 2`, `1 and 3`, `2 and 4`, `3 and 4`], e: `Given: 1. Bhopal Head Office Bhopal GPO Campus ­ 462001 2. Bhopal Head Office Bhopal GPO Campus ­ 462001 3. Bhopal Head Office Bhopal PPO Campus ­ 462001 4. Bhopal Head Office Bhopal GPO Campas ­ 462001 Now, we check each options. Option (a): 1 and 2 Both entries are letter-by-letter identical Same words, same spelling, same PIN code Exactly the same Option (b): 1 and 3 Entry 1: GPO Campus Entry 3: PPO Campus Different words Not same Option (c): 2 and 4 Entry 2: GPO Campus Entry 4: GPO Campas Spelling differs (Campus vs Campas) Not exactly same O ption (d): 3 and 4 Entry 3: PPO Campus Entry 4: GPO Campas Different words and spelling Not same So, 1 and 2 are exactly same. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Some equations are defined using symbols and mathematical relations. Identify the correct value. If X Y = (X - Y)² + Y, then 7 3 is?`, o: [`19`, `20`, `21`, `22`], e: `Given: If X Y = (X - Y)² + Y, then 7 3 is? Substitute X = 7 and Y = 3: 7 3 = (7 - 3)2+ 3 = 42+ 3 = 16 + 3 = 19 Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In the following question, the second term is derived from the first term by applying a specific pattern involving alphabetical positions and alphanumeric manipulation. Decode the logic and apply it to the second pair. COLD : P27D :: WARM : ?`, o: [`J28M`, `H19M`, `G28M`, `J19M`], e: `Given: COLD : P27D :: WARM : ? Logic: 1st letter + 13, 4th letter same and sum of middle two letters = Number For, COLD : P27D C + 13 = P 15 + 12 = 27 D=D Similarly, WARM : ? W + 13 = J 1 + 18 = 19 M=M So, WARM : J19M Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `In a family tree: · A is the mother of B · B is the sister of C · C is the father of D. What is A's relation to D?`, o: [`Grandmother`, `Aunt`, `Mother`, `Sister`], e: `Given: In a family tree: · A is the mother of B · B is the sister of C · C is the father of D. From the given information blood relation diagram will be. So, A is grandmother of D. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `What will come at the place of question mark? 4, 20, 120, 840, ?`, o: [`6720`, `7560`, `8400`, `7200`], e: `Given: 4, 20, 120, 840, ? Logic: Numbers are multiply by natural number from 5. 4 × 5 = 20 20 × 6 = 120 120 × 7 = 840 840 × 8 = 6720 So, the missing term is 6720. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Find the missing number in the series: 2, 6, 12, 20, ?`, o: [`28`, `30`, `32`, `36`], e: `Given: 2, 6, 12, 20, ? Logic: Numbers are increasing even number from 4. 2+4=6 6 + 6 = 12 12 + 8 = 20 20 + 10 = 30 So, the missing term is 30. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Three of the following four groups are alike in a certain pattern. Find the one which does not belong to the group.`, o: [`ABCD`, `MNOP`, `WXYZ`, `ABDC`], e: `Logic: 1st letter + 1 = 2nd letter, 2nd letter + 1 = 3rd letter and 3rd letter + 1 = 4th letter Now, we check each options. Option (a): ABCD A + 1 = B, B + 1 = C, C + 1 = D O ption (b): MNOP M + 1 = N, N + 1 = O, O + 1 = P O ption (c): W XYZ W + 1 = X, X + 1 = Y, Y + 1 = Z O ption (d): ABDC A + 1 = B, B + 1 =D, D + 1 = C So, ABDC is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Unscramble the letters to make a meaningful word that fits one of the given categories: LPAENET`, o: [`City`, `Animal`, `Planet`, `River`], e: `Given: LPAENET Now, looking at the options: Option (a): City - (PLANET is not a city) Option (b): Animal - (PLANET is not an animal) Option (c): Planet - (PLANET itself is a category) Option (d): River - (PLANET is not a river) By rearranging these letters, we can form the word PLANET. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Statement: A team leader prefers a familiar software tool over a newer, more efficient one because the old tool has been used for years without major issues. Question: Which cognitive bias is influencing the decision, and how should it be addressed?`, o: [`Anchoring bias; rely only on first impressions`, `Status quo bias; compare options using current performance data`, `Confirmation bias; ignore feedback from others`, `Availability bias; choose what is most memorable`], e: `Statement: A team leader prefers a familiar software tool over a newer, more efficient one because the old tool has been used for years without major issues. Question: Which cognitive bias is influencing the decision, and how should it be addressed? Explanation: The team leader is choosing the old software just because it has been used for many years without problems, even though a newer and more efficient option exists. This shows a preference for sticking with what is familiar instead of evaluating better alternatives. This behavior reflects status quo bias, where people resist change and prefer existing conditions. The best way to address this bias is to compare both software tools using current performance data and make a decision based on facts rather than habit. So, Status quo bias; ` },
  { s: `General Intelligence`, q: `If 48 is coded as 2, 6, 8, then what is the code for 75?`, o: [`3, 5, 15`, `5, 15, 25`, `3, 15, 25`, `5, 25, 75`], e: `Given: If 48 is coded as 2, 6, 8. Logic: The code consists of numbers that are factors of the given number (excluding 1 and the number itself). Factors of 48 2, 6, 8 S imilarly, 75 ? Factors of 75 3, 5, 15 So, 3, 5, 15 is the code for 75. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In the following question, select the number that will replace the question mark (?) to complete the analogy: 64 : 343 :: 36 : ?`, o: [`125`, `216`, `256`, `196`], e: `Given: 64 : 343 :: 36 : ? Logic: (The square root of the first number - 1)3= 2nd number For, 64 : 343 64 = 8, 8 - 1 = 7, 73= 343 Similarly, 36 : ? 36 = 6, 6 - 1 = 5, 53= 125 Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Few letters are given followed by a question mark (?). These letters follow a specific pattern. Choose the correct option that can replace the question mark. CC, FF, JJ, OO, ?`, o: [`TT`, `SS`, `RR`, `UU`], e: `Given: CC, FF, JJ, OO, ? Logic: Letters are increasing natural number from 3. C + 3 = F, F + 4 = J, J + 5 = O, O + 6 = U C + 3 = F, F + 4 = J, J + 5 = O, O + 6 = U So, the missing term is UU. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Read the following scenario carefully and choose the most appropriate course of action. Scenario: You notice that a colleague has repeatedly missed deadlines, affecting team performance. They seem stressed but deny any problem. Question: What should you do?`, o: [`Report the colleague immediately to senior management for disciplinary action.`, `Ignore the situation and adjust your own work to compensate for the delays.`, `Speak to the colleague privately to understand the issue and help find a solution.`, `Publicly warn the colleague during a team meeting to improve accountability.`], e: `Scenario: You notice that a colleague has repeatedly missed deadlines, affecting team performance. They seem stressed but deny any problem. Explanation: The best thing to do is to talk to the colleague privately. This helps you understand what is causing the missed deadlines and gives you a chance to support them in finding a solution. It is respectful and helps improve team performance. Reporting immediately, ignoring the issue, or warning them publicly could make the situation worse. So, Speak to the colleague privately to understand the issue and help find a solution should you do. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Each question has four options. Three of them go together based on a common rule. One is different. Identify the odd one.`, o: [`6 : 21`, `7 : 28`, `8 : 36`, `9 : 40`], e: `Logic: 1st number × (1st number + 1) ÷ 2 = 2nd number Now, we check each options. Option (a): 6 : 21 6 × (6 + 1) ÷ 2 = (6 × 7) ÷ 2 = 42 ÷ 2 = 21 O ption (b): 7 : 28 7 × (7 + 1) ÷ 2 = (7 × 8) ÷ 2 = 56 ÷ 2 = 28 O ption (c): 8 : 36 8 × (8 + 1) ÷ 2 = (8 × 9) ÷ 2 = 72 ÷ 2 = 36 Option (d): 9 : 40 9 × (9 + 1) ÷ 2 = (9 × 10) ÷ 2 = 90 ÷ 2 =40 So, 9 : 40 is odd one out. Thus, correct option is (d).` },
  { s: `General Awareness`, q: `Iso-cost line is also known as ________ line.`, o: [`budget`, `Output`, `demand`, `revenue`], e: `The correct answer is (a) Budget Explanation: An Iso-cost line represents all combinations of two factors of production (like labor and capital) that a firm can purchase with a specific total budget. It is called a Budget line or Budget constraint line for a firm because it shows the financial limit within which the firm must operate. The equation for an iso-cost line is typically expressed as $C = (w \\cdot L) + (r \\cdot K)$, where $C$ is total cost, $w$ is wage, $L$ is labor, $r$ is rent, and $K$ is capital. The slope of the iso-cost line is the ratio of the prices of the inputs ($w/r$), representing the market rate of substitution. Any point on the line indicates that the firm is spending its entire allocated budget on the inputs. Information Booster: In consumer theory, a similar concep` },
  { s: `General Awareness`, q: `The concept of "sustainable development" emphasizes:`, o: [`Unlimited industrial growth without environmental concerns`, `Meeting present needs without compromising the ability oCfofpuytruigrehtg©ene2r0a2t6ioAnds dtoa2m47eet their own needs`, `Maximizing GDP irrespective of resource depletion`, `Promoting only urban development`], e: `The correct answer is (B) Meeting present needs without compromising the ability of future generations to meet their own needs Explanation: · Sustainable development is a holistic approach that seeks to balance economic growth with environmental protection and social equity. · It was famously defined in the 1987 Brundtland Commission Report (Our Common Future). Information Booster: · The United Nations has established 17 Sustainable Development Goals (SDGs) to be achieved by 2030. Additional Knowledge: · Option A & C: Describe unsustainable growth patterns that ignore environmental carrying capacity.` },
  { s: `General Awareness`, q: `Which Article of the Indian Constitution provides for the abolition of untouchability?`, o: [`Article 15`, `Article 16`, `Article 17`, `Article 18`], e: `The correct answer is (C) Article 17 Explanation: · Article 17 abolishes 'Untouchability' and forbids its practice in any form. · It is a fundamental right available against both the state and private individuals. Information Booster: · The Untouchability (Offences) Act, 1955 was later renamed the Protection of Civil Rights Act, 1955. Additional Knowledge: · Article 15 (Option A): Prohibition of discrimination on grounds of religion, race, caste, sex or place of birth. · Article 16 (Option B): Equality of opportunity in matters of public employment. · Article 18 (Option D): Abolition of titles.` },
  { s: `General Awareness`, q: `Which cell organelle is known as the "powerhouse of the cell"?`, o: [`Ribosome`, `Chloroplast`, `Mitochondria`, `Nucleus`], e: `The correct answer is (C) Mitochondria Explanation: · Mitochondria are responsible for cellular respiration and generating ATP (Adenosine Triphosphate), the energy currency of the cell. · They contain their own DNA and ribosomes. Information Booster: · Mitochondria were first observed by Albert von Kolliker in 1880. Additional Knowledge: · Ribosome (Option A): Known as the protein factory. · Chloroplast (Option B): Known as the kitchen of the cell (in plants). · Nucleus (Option D): Known as the brain or control center of the cell.` },
  { s: `General Awareness`, q: `Which statement is correct about India's performance inCothpeyrIiCgChtC©ric2k0e2t6WAodrdlda2C4u7p 2011?`, o: [`India lost in the semi-finals to Australia.`, `India defeated Sri Lanka in the final to win the title.`, `India did not qualify for the knockout stage.`, `The tournament was hosted only by India.`], e: `The correct answer is (B) India defeated Sri Lanka in the final to win the title. Explanation: · India won the 2011 World Cup by defeating Sri Lanka by 6 wickets in the final held at Wankhede Stadium, Mumbai. · This was India's second ODI World Cup win (first was in 1983). Information Booster: · Yuvraj Singh was named the 'Player of the Tournament'. Additional Knowledge: · Option D: The tournament was joint-hosted by India, Sri Lanka, and Bangladesh.` },
  { s: `General Awareness`, q: `Which among the following pairs is NOT correctly matched about Indian classical dance forms and their states?`, o: [`Kathak ­ Uttar Pradesh`, `Bharatanatyam ­ Tamil Nadu`, `Kuchipudi ­ Kerala`, `Odissi ­ Odisha`], e: `The correct answer is (C) Kuchipudi ­ Kerala Explanation: · Kuchipudi is a classical dance form from Andhra Pradesh, not Kerala. · Kerala is famous for Kathakali and Mohiniyattam. Information Booster: · There are 8 recognized classical dance forms by Sangeet Natak Akademi. Additional Knowledge: · Kathak (Option A): North India (UP). · Bharatanatyam (Option B): Tamil Nadu. · Odissi (Option D): Odisha.` },
  { s: `General Awareness`, q: `What is the primary objective of the Gaganyaan Mission launched by ISRO?`, o: [`Launching communication satellites`, `Sending Indian astronauts into space`, `Exploring Mars surface`, `Studying ocean currents`], e: `The correct answer is (B) Sending Indian astronauts into space Explanation: · Gaganyaan is India's first human spaceflight mission. · It aims to demonstrate indigenous capability to undertake human space flight to Low Earth Orbit (LEO). Information Booster: · Vyommitra, a female-looking humanoid robot, was developed by ISRO to accompany the uncrewed mission. Additional Knowledge: · Mars Exploration (Option C): Associated with the Mangalyaan mission (MOM).` },
  { s: `General Awareness`, q: `Which Constitutional Amendment lowered the voting age from 21 years to 18 years in India?`, o: [`42nd Amendment`, `44th Amendment`, `61st Amendment`, `73rd Amendment`], e: `The correct answer is (C) 61st Amendment Explanation: · The 61st Constitutional Amendment Act, 1988 reduced the voting age for elections to the Lok Sabha and State Legislative Assemblies. · It amended Article 326 of the Constitution. Information Booster: · This amendment was enacted during the Prime Ministership of Rajiv Gandhi. Additional Knowledge: · 42nd Amendment (Option A): Known as the Mini-Constitution. · 44th Amendment (Option B): Corrected distortions introduced during the Emergency. · 73rd Amendment (Option D): Related to Panchayati Raj.` },
  { s: `General Awareness`, q: `In Hindustani classical music, which instrument is primarily used to maintain the rhythmic cycle (taal)?`, o: [`Tabla`, `Sitar`, `Flute`, `Violin`], e: `The correct answer is (A) Tabla Explanation: · The Tabla is a pair of twin hand drums and is the principal percussion instrument in Hindustani music. · It provides the 'Taal' or rhythmic framework for the performance. Information Booster: · Zakir Hussain and Allah Rakha are legendary Tabla players. Additional Knowledge: · Sitar (Option B): A plucked string instrument. · Flute (Option C): A woodwind instrument. · Violin (Option D): A bowed string instrument (very common in Carnatic music).` },
  { s: `General Awareness`, q: `Which of the following agencies is responsible for managing India's space research and satellite launches?`, o: [`DRDO`, `ISRO`, `NASA`, `HAL`], e: `The correct answer is (B) ISRO Explanation: · ISRO (Indian Space Research Organisation) is the national space agency of India. · It operates under the Department of Space (DoS). Information Booster: · ISRO was formed on August 15, 1969, replacing INCOSPAR. Additional Knowledge: · DRDO (Option A): Responsible for military research and development. · NASA (Option C): Space agency of the USA. · HAL (Option D): Primarily involved in aerospace and defense manufacturing.` },
  { s: `General Awareness`, q: `Which of the following is an example of an endothermic reaction?`, o: [`Combustion of coal`, `Respiration`, `Melting of ice`, `Burning of LPG`], e: `The correct answer is (C) Melting of ice Explanation: · An endothermic reaction is a chemical or physical process that absorbs heat from its surroundings. · Melting of ice requires heat energy to break the bonds between water molecules. Information Booster: · Photosynthesis is a critical biological endothermic reaction as it absorbs solar energy. Additional Knowledge: · Combustion and Burning (Options A & D): These are exothermic reactions because they release energy (heat/light). · Respiration (Option B): An exothermic process where energy is released for cellular functions.` },
  { s: `General Awareness`, q: `Read the following statements marked as Assertion (A) and Reason (R). Mark the correct option: Assertion (A): The monsoon winds in India are seasonal in nature. Reason (R): The differential heating of land and sea causes seasonal reversal of wind direction.`, o: [`Both A and R are true, and R is the correct explanation of A.`, `Both A and R are true, but R is not the correct explanation of A.`, `A is true, but R is false.`, `A is false, but R is true.`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A. Explanation: · The term 'monsoon' refers to the seasonal reversal in wind direction. · The primary cause is the difference in temperature between the landmass and the surrounding oceans, which creates pressure gradients. Information Booster: · During summer, the interior of the continent becomes hot, creating low pressure that draws in moist air from the high-pressure sea. Additional Knowledge: · The Indian monsoon is divided into two phases: South-West monsoon and North-East monsoon.` },
  { s: `General Awareness`, q: `Which of the following is NOT a rabi crop? 1. Wheat 2. Gram 3. Rice 4. Mustard 5. Barley 6. Peas`, o: [`1, 2, 5`, `3`, `3, 4, 6`, `2, 4, 6`], e: `The correct answer is (B) 3 Explanation: · Rabi crops are sown in winter (October-December) and harvested in spring (April-June). · Rice is a Kharif crop, sown with the onset of monsoon and harvested in September-October. Information Booster: · Wheat, Gram, Mustard, Barley, and Peas are all classic examples of Rabi crops. Additional Knowledge: · Kharif crops include Rice, Maize, Jowar, Bajra, Tur, Moong, Urad, Cotton, Jute, Groundnut, and Soyabean.` },
  { s: `General Awareness`, q: `Who launched the PM Gati Shakti National Master Plan in India?`, o: [`Narendra Modi`, `Amit Shah`, `Nitin Gadkari`, `Piyush Goyal`], e: `The correct answer is (A) Narendra Modi Explanation: · PM Gati Shakti was launched by Prime Minister Narendra Modi in October 2021. · It is a digital platform to bring 16 Ministries together for integrated planning and coordinated implementation of infrastructure connectivity projects. Information Booster: · The plan aims to improve logistics efficiency and reduce supply chain costs. Additional Knowledge: · It focuses on seven engines: Railways, Roads, Ports, Waterways, Airports, Mass Transport, and Logistics Infrastructure.` },
  { s: `General Awareness`, q: `Which of the following statements accurately describes the book \`Wings of Fire' by A.P.J. Abdul Kalam?`, o: [`A fictional novel on space exploration`, `Autobiography of A.P.J. Abdul Kalam`, `A detailed study of India's foreign policy`, `A scientific textbook on missile technology`], e: `The correct answer is (B) Autobiography of A.P.J. Abdul Kalam Explanation: · 'Wings of Fire' (1999) covers the early life of Dr. Kalam and his work in Indian space and missile programs. · It was co-written by Arun Tiwari. Information Booster: · Dr. Kalam is also known as the 'Missile Man of India'. Additional Knowledge: · Other books by Dr. Kalam: 'India 2020', 'Ignited Minds', and 'Indomitable Spirit'.` },
  { s: `General Awareness`, q: `Which Article of the Constitution empowers the Supreme Court to transfer cases from one High Court to another?`, o: [`Article 131`, `Article 139A`, `Article 226`, `Article 142`], e: `The correct answer is (B) Article 139A Explanation: · Article 139A allows the Supreme Court to transfer cases involving similar questions of law from one High Court to another or to itself. · This ensures uniform interpretation of the law across the country. Information Booster: · This power was inserted by the 42nd Amendment Act, 1976. Additional Knowledge: · Article 131 (Option A): Original jurisdiction of the Supreme Court. · Article 226 (Option C): Power of High Courts to issue writs. · Article 142 (Option D): Power to pass 'complete justice' decrees.` },
  { s: `General Awareness`, q: `Read the following statements marked as Assertion (A) and Reason (R). Assertion (A): The Non-Cooperation Movement was launched in 1920. Reason (R): It was started in response to the Jallianwala Bagh massacre and the Khilafat issue.`, o: [`Both A and R are true, and R is the correct explanation of A.`, `Both A and R are true, but R is not the correct explanation of A.`, `A is true, but R is false.`, `A is false, but R is true.`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A. Explanation: · The movement was formally launched by Mahatma Gandhi in August 1920. · The grievances included the Rowlatt Act, the Jallianwala Bagh massacre, and the perceived injustice to Turkey (Khilafat). Information Booster: · The movement was called off in 1922 after the Chauri Chaura incident. Additional Knowledge: · The 'Tilak Swaraj Fund' was started during this movement to collect funds for the struggle.` },
  { s: `General Awareness`, q: `Which of the following pairs of Mughal rulers and their immediate successors is correctly matched?`, o: [`Humayun ­ Jahangir`, `Akbar ­ Jahangir`, `Jahangir ­ Aurangzeb`, `Shah Jahan ­ Akbar`], e: `The correct answer is (b) Akbar ­ Jahangir Explanation: Jahangir (Salim) was the eldest son of Akbar and succeeded him to the Mughal throne in 1605. Akbar, the third Mughal emperor, reigned from 1556 to 1605, expanding the empire across most of the Indian subcontinent. The transition of power from Akbar to Jahangir was relatively stable, marking the continuation of the "Great Mughals" era. Jahangir is known for his patronage of Mughal painting and the establishment of the "Chain of Justice" (Zanjir-i-Adl). Under Jahangir's reign, the empire maintained the administrative and religious policies largely initiated by Akbar. Information Booster: The Mughal Dynasty was founded by Babur in 1526 after the First Battle of Panipat, where he defeated Ibrahim Lodi. The chronological order of the promi` },
  { s: `General Awareness`, q: `Consider the following statements about the Quad grouping (India, USA, Japan, Australia): 1. The Quad was revived in 2017. 2. It primarily focuses on promoting a free and open Indo-Pacific region. 3. China is a permanent member of the Quad. Which of the above statements is/are correct?`, o: [`1 and 2 only`, `2 and 3 only`, `1 and 3 only`, `1, 2 and 3`], e: `The correct answer is (A) 1 and 2 only Explanation: · The Quadrilateral Security Dialogue (Quad) consists of India, US, Japan, and Australia. · Statement 3 is incorrect as China is not a member; in fact, the grouping is often seen as a counter-balance to China's influence. Information Booster: · The concept was originally initiated by Japan's Shinzo Abe in 2007 but was revived in 2017. Additional Knowledge: · Quad countries participate in the Malabar naval exercise.` },
  { s: `General Awareness`, q: `Which of the following statements about the Goods and Services Tax (GST) Council is/are correct? 1. It is chaired by the Union Finance Minister. 2. It includes the Finance Ministers of all States. 3. Its decisions are binding without any voting mechanism.`, o: [`1 and 2 only`, `2 and 3 only`, `1 and 3 only`, `1, 2 and 3`], e: `The correct answer is (A) 1 and 2 only Explanation: · The GST Council is a constitutional body (Article 279A). · Statement 3 is incorrect because decisions are made by a three-fourths majority of the weighted votes of the members present and voting. Information Booster: · The Union Government has a weightage of one-third of the total votes cast. Additional Knowledge: · The States have a combined weightage of two-thirds of the total votes cast.` },
  { s: `General Awareness`, q: `Which of the following rivers flows into the Arabian Sea?`, o: [`Godavari`, `Krishna`, `Narmada`, `Mahanadi`], e: `The correct answer is (C) Narmada Explanation: · While Narmada originates in Amarkantak (Maikal range, not technically the Western Ghats proper but often grouped in western flow discussion), among the options, it is the only major west-flowing river entering the Arabian Sea. · However, technically Narmada/Tapi are rift valley rivers. If the question implies 'originates west and flows west', Narmada is the fit here despite the specific origin nuance. Information Booster: · Most major peninsular rivers flow East (Bay of Bengal) due to the tilt of the plateau. Additional Knowledge: · Godavari, Krishna, Mahanadi (Options A, B, D): All flow into the Bay of Bengal.` },
  { s: `General Awareness`, q: `Read the following two statements carefully and choose the correct option: Statement 1: The 73rd Constitutional Amendment Act deals with Panchayati Raj Institutions. Statement 2: It added Part IX to the Constitution of India.`, o: [`Only 1`, `Only 2`, `Both 1 and 2 are correct`, `Neither 1 nor 2 is correct`], e: `The correct answer is (C) Both 1 and 2 are correct Explanation: · The 73rd Amendment Act, 1992 gave constitutional status to Panchayati Raj Institutions. · It added Part IX (Articles 243 to 243O) and the 11th Schedule to the Constitution. Information Booster: · April 24th is celebrated as National Panchayati Raj Day. Additional Knowledge: · The 74th Amendment Act deals with Municipalities (Urban Local Bodies) and added Part IXA.` },
  { s: `General Awareness`, q: `Match the space mission with its primary objective: 1. Chandrayaan-1 - Moon exploration 2. Gaganyaan - Human spaceflight 3. Astrosat - Space observatory`, o: [`1­Human spaceflight, 2­Moon exploration, 3­Mars study`, `1­Moon exploration, 2­Human spaceflight, 3­Space observatory`, `1­Mars orbit, 2­Sun study, 3­Lunar rover`, `1­Space observatory, 2­Mars orbit, 3­Human spaceflight`], e: `The correct answer is (B) 1­Moon exploration, 2­Human spaceflight, 3­Space observatory Explanation: · Chandrayaan-1 was India's first mission to the Moon (2008). · Gaganyaan is the upcoming human spaceflight mission. · Astrosat is India's dedicated multi-wavelength space observatory. Information Booster: · Chandrayaan-1 discovered evidence of water molecules on the lunar surface. Additional Knowledge: · Mangalyaan (MOM) was India's mission to Mars (2013). · Aditya-L1 is the first Indian mission to study the Sun.` },
  { s: `General Awareness`, q: `Which of the following is a macroeconomic objective of the 1991 Economic Reforms in India?`, o: [`Nationalization of private banks`, `Increasing import restrictions`, `Liberalization of trade and industry`, `Abolition of private sector participation`], e: `The correct answer is (C) Liberalization of trade and industry Explanation: · The 1991 New Economic Policy introduced LPG (Liberalization, Privatization, and Globalization). · It aimed to reduce government control, end the 'License Raj', and open the economy to global markets. Information Booster: · Dr. Manmohan Singh was the Finance Minister when these reforms were introduced under P.V. Narasimha Rao's government. Additional Knowledge: · Options A, B, & D: These represent pre-1991 'command economy' characteristics which the reforms sought to replace.` },
  { s: `General Awareness`, q: `Match the Constitutional Amendment with its key feature: 1. 42nd Amendment Act - Added Fundamental Duties 2. 44th Amendment Act - Restored certain Emergency provisions 3. 73rd Amendment Act - Panchayati Raj Institutions`, o: [`1­Right to Property removed from Fundamental Rights, 2­Added Fundamental Duties, 3­Panchayati Raj`, `1­Added Fundamental Duties, 2­Restored certain Emergency provisions, 3­Panchayati Raj Institutions`, `1­Panchayati Raj, 2­Added Fundamental Duties, 3­Emergency provisions`, `1­Emergency provisions strengthened, 2­Panchayati Raj, 3­Added Fundamental Duties`], e: `The correct answer is (B) 1­Added Fundamental Duties, 2­Restored certain Emergency provisions, 3­Panchayati Raj Institutions Explanation: · 42nd Amendment (1976): Added Part IVA (Fundamental Duties). · 44th Amendment (1978): Corrected emergency abuse by requiring 'written advice' from the Cabinet. · 73rd Amendment (1992): Constitutionalized Panchayati Raj. Information Booster: · The 44th Amendment also moved the 'Right to Property' from Fundamental Rights to Legal Rights (Article 300A). Additional Knowledge: · The 42nd Amendment added the words 'Socialist', 'Secular', and 'Integrity' to the Preamble.` },
  { s: `Quantitative Aptitude`, q: `Find the value of: 1/(3 − √8) − 1/(3 + √8) + 6/(9 − 8)`, o: [`4√2 + 6`, `4√2`, `6`, `3√2 + 6`], e: `Rationalize: 1/(3−√8) = (3+√8), 1/(3+√8) = (3−√8). (3+√8) − (3−√8) + 6 = 2√8 + 6 = 4√2 + 6. Option A.` },
  { s: `Quantitative Aptitude`, q: `Two cars start from places A and B, 100 km apart, towards each other and meet in 1 hour. If they travel in the same direction, they meet in 5 hours. Find the speed of the faster car.`, o: [`60 km/h`, `40 km/h`, `70 km/h`, `80 km/h`], e: `Given: Distance = 100 km. Opposite direction meeting time = 1 hr. Same direction meeting time = 5 hrs. Formula Used: Relative Speed (Opposite) = u + v = D/t Relative Speed (Same) = u - v = D/t Solution: Let speeds be u and v (u > v). 100 u + v = = 100 1010 u - v = = 20 5 Adding both equations: 2u = 120 u = 60 km/h The faster speed is 60 km/h. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The difference between CI and SI on a certain sum for 2 years at 15% per annum is 225. Find the sum.`, o: [`8,000`, `9,000`, `10,000`, `12,000`], e: `Given: Difference (D) = 225. Time (t) = 2 years. Rate (R) = 15%. Formula Used: For 2 years, D = P ( R2 ) 100 Solution: Substitute values: 15 2 225 = P ( ) 100 32 225 = P ( ) 20 9 225 = P ( ) 400 225 × 400 P= 9 P = 25 × 400 P = 10, 000 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A cricketer has an average of 45 runs in 14 innings. How many runs must he score in the 15th inning to increase his average to 47?`, o: [`70`, `75`, `68`, `72`], e: `Given: Average of 14 innings = 45. Target Average after 15 innings = 47. Formula Used: Total = Average \\times Number of Innings Solution: Total runs in 14 innings = 14 × 45 = 630. Total runs required in 15 innings = 15 × 47 = 705. Runs to score in 15th inning = 705 - 630 = 75 Alternate Method: Increase in average = 2. Total increase = 15 × 2 = 30. Score = 45 + 30 = 75. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The profit made by selling an article for 1200 is equal to the loss incurred by selling it for 900. What should be the selling price to gain 20%?`, o: [`1260`, `1300`, `1150`, `1250`], e: `Given: Profit at SP 1200 = Loss at SP 900. Desired Gain = 20%. Formula Used: Profit = SP - CP; Loss = CP - SP Solution: Let CP be x. 1200 - x = x - 900 2x = 2100 x = 1050 CP = 1050. 120 For 20% gain, SP = 1050 × 100 = 1050 × 1.2 = 1260 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Find the value of (3/x + 3x)(9/x² − 9 + 9x²) if x = 2.`, o: [`1755/8`, `1865/8`, `1701/8`, `1650/8`], e: `Using identity (a+b)(a²−ab+b²) = a³+b³ with a = 3/x, b = 3x: result = 27/x³ + 27x³. At x=2: 27/8 + 216 = 27/8 + 1728/8 = 1755/8. Option A.` },
  { s: `Quantitative Aptitude`, q: `A merchant mixes 30 kg of tea at 400/kg with 20 kg of tea at 500/kg. He sells the mixture at 480/kg. What is his profit percentage?`, o: [`8.5%`, `9.09%`, `10%`, `11.11%`], e: `Given: Tea A: 30 kg at 400/kg. Tea B: 20 kg at 500/kg. Selling Price of Mixture = 480/kg. Formula Used: Profit % = SP - CP × 100 CP Solution: Total Cost Price = (30 × 400) + (20 × 500)= 12000 + 10000 = 22000. Total Weight = 30 + 20 = 50 kg. Average CP per kg = 22000 = 440. 50 Profit per kg = 480 - 440 = 40. 40 Profit % = × 100 440 = 1 × 100 11 = 9.09% Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `What percent of 0.1 cubic meters is 50,000 cubic centimeters?`, o: [`25%`, `50%`, `10%`, `5%`], e: `Given: Total volume = 0.1 m3. Part volume = 50,000 cm3. Formula Used: 1 m3= 1,000,000 cm3 Percentage = Part × 100 Total Solution: Convert 0.1 m3to cm3: 0.1 × 1, 000, 000 = 100, 000 cm3. Calculate percentage: 50, 000 × 100 100, 000 1 1 = × 100 2 = 50% Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Two chords AB and CD of a circle intersect intersect at a point P inside the circle. If AP = 10 cm, PB = 6 cm, and CP = 4 cm, find the length of PD.`, o: [`12 cm`, `15 cm`, `18 cm`, `14 cm`], e: `Given: Chords AB and CD intersect at P. AP = 10 cm, PB = 6 cm, CP = 4 cm. Formula Used: Intersecting Chords Theorem: AP PB = CP P D Solution: Substitute the given values into the formula: 10 6 = 4 P D 60 = 4 P D 60 PD = 4 P D = 15 cm Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `In a factory, Machine A produces 70% of the items and Machine B produces 30%. 2% of A's production is defective and 5% of B's production is defective. If an item is selected at random and found to be defective, what is the probability it came from Machine B?`, o: [`15/29`, `14/29`, `12/29`, `10/29`], e: `Given: P(A) = 0.70, P(B) = 0.30. P(D|A) = 0.02, P(D|B) = 0.05. Formula Used: P (DB)P (B) Bayes' Theorem: P(B|D) = P (DA)P (A) + P (DB)P (B) Solution: Numerator: P(D|B)P(B) = 0.05 × 0.30 = 0.015. Denominator: (0.02 × 0.70) + (0.05 × 0.30) = 0.014 + 0.015 = 0.029. 0.015 15 Probability = =. 0.029 29 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `An equilateral triangle and a square have the same perimeter. What is the ratio of the area of the triangle to the area of the square?`, o: [`3`, `4 : 3`, `4`, `9 : 4`], e: `Given: Perimeter of Equilateral Triangle = Perimeter of Square. Formula Used: Area of Triangle = 4 3 a2 Area of Square = s2 Solution: Let side of triangle be a and square be s. 4s 3 a = 4s a = . 3 3 4s 2 Area of Triangle = ( ) 43 = 3 16s2 49 = 4 9 3 s .2 Area of Square = s2. 4 3s2 : s2 = 4 3 : 9. Ratio = 9 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `An arc of a circle of radius 21 cm subtends an angle of 60at the center. Find the length of the arc. (Use = 22/7)`, o: [`11 cm`, `22 cm`, `33 cm`, `44 cm`], e: `Given: Radius r = 21 cm. Angle = 60. Formula Used: Length of Arc = × 2r 360 Solution: 60 22 L = × 2 × × 21 360 7 1 L = × 44 × 3 6 L = 132 6 L = 22 cm. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A sphere is inscribed in a hemisphere of radius R such that it touches the curved surface and the plane base. What is the radius of this inscribed sphere?`, o: [`R/2`, `R/3`, `R/ 2`, `2R/3`], e: `Given: Hemisphere radius R. Sphere inscribed touching curved surface and base. Formula Used: Geometric property of inscribed sphere in hemisphere. Solution: Let r be the radius of the inscribed sphere. The sphere sits on the base, so its center is at height r. The top of the sphere touches the highest point of the hemisphere. Total height from base to top of sphere = 2r. This height corresponds to the radius of the hemisphere R (at the pole). Therefore, 2r = R r = R/2. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A right prism has a regular hexagonal base of side 6 cm. If the height of the prism is 10 cm, find its lateral surface area.`, o: [`360 cm2`, `300 cm2`, `240 cm2`, `420 cm2`], e: `Given: Base: Regular hexagon, side a = 6 cm. Height h = 10 cm. Formula Used: LSA of Prism = Perimeter of Base × Height Solution: Perimeter of hexagon = 6a = 6 × 6 = 36 cm. Lateral Surface Area = 36 × 10 = 360 cm2. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `If sec + tan = 3, find the value of \\tan .`, o: [`3/4`, `4/3`, `1/3`, `5/3`], e: `Given: sec + tan = 3. Formula Used: sec2 - tan2 = 1 (sec - tan )(sec + tan ) = 1 Solution: 1 We get sec - tan = . 3 Subtract this from the given equation: 1 (sec + tan ) - (sec - tan ) = 3 - 3 8 2 tan = 43 tan = 3 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `From the top of a 60 m high tower, the angle of depression of a car moving away changes from 45^\\circ to 30^\\circ in 5 seconds. What is the speed of the car?`, o: [`12(`, `12 3m/s`, `10(`, `15( 3 - 1)m/s`], e: `Given: Height h = 60 m. Angle changes from 45to 30in 5 seconds. Formula Used: Distance = Height × cot() Speed = Distance / Time Solution: Initial distance d1 = 60 cot 45= 60(1) = 60 m. Final distance d2 = 60 cot 30 = 60 3m . Distance traveled = 60 3 - 60 = 60( 3 - 1)m . 60( 3 - 1) = 12( 3 1) m/s. Speed = 5 - Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `What is the largest 4-digit number that is exactly divisible by 72?`, o: [`9936`, `9960`, `9984`, `9992`], e: `Given: Divisor = 72. We need the largest 4-digit number divisible by 72. Formula Used: Dividend = Divisor × Quotient + Remainder Solution: The largest 4-digit number is 9999. Divide 9999 by 72: 9999 ÷ 72 = 138 with a remainder of 63 To find the largest divisible number, subtract the remainder from 9999: Number = 9999 - 63 Number = 9936 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Simplify (√3 + √7)².`, o: [`10 + 2√21`, `10 + √21`, `√21 + 2√10`, `5 + 2√21`], e: `(√3 + √7)² = 3 + 7 + 2√21 = 10 + 2√21. Option A.` },
  { s: `Quantitative Aptitude`, q: `A can do a work in 12 days and B in 15 days. They contract to do the work for 9,600. With the help of C, they finish it in 5 days. How much does C get?`, o: [`2,000`, `2,400`, `2,800`, `3,000`], e: `Given: A's time = 12 days, B's time = 15 days. A + B + C time = 5 days. Total wages = 9600. Formula Used: Wages are distributed in proportion to efficiency (work done per day). Solution: Let Total Work = 60 units (LCM of 12, 15, 5). Efficiency of A = 60/12 = 5 units/day. Efficiency of B = 60/15 = 4 units/day. Efficiency of (A+B+C) = 60/5 = 12 units/day. Efficiency of C = 12 - (5 + 4) = 3 units/day. Ratio of shares A:B:C = 5:4:3. Total parts = 12. 3 C's share = × 9600 12 1 = × 9600 4 = 2400 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A and B invest 50,000 and 70,000. After one year, the total profit is 24,000. What is A's share of the profit?`, o: [`10,000`, `14,000`, `12,000`, `9,000`], e: `Given: Investment of A = 50,000. Investment of B = 70,000. Total Profit = 24,000. Formula Used: Profit Share Investment ×Time Solution: Since the time period is the same (1 year), the ratio of profit is the ratio of investments. Ratio A : B = 50,000 : 70,000 = 5 : 7. Total parts = 5 + 7 = 12. 5 A's share = × 24, 000 12 = 5 × 2, 000 = 10,000 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `What is the x-intercept of the line 5x + 3y = 15?`, o: [`5`, `3`, `15`, `2`], e: `Given: Line: 5x + 3y = 15. Formula Used: For x-intercept, set y = 0. Solution: 5x + 3(0) = 15 5x = 15 x = 3. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `PA and PB are tangents to a circle from an external point P. If the length of PA is 12 cm, what is the length of PB?`, o: [`10 cm`, `12 cm`, `24 cm`, `6 cm`], e: `Given: Tangents PA and PB from P. PA = 12 cm. Formula Used: Lengths of tangents from an external point to a circle are equal. Solution: PA = PB. Since PA = 12 cm, PB = 12 cm. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `In triangle ABC, the area is 60 cm2 and the product of the lengths of its three sides is 2400. Find the circumradius of the triangle.`, o: [`8 cm`, `10 cm`, `12 cm`, `15 cm`], e: `Given: Area A = 60 cm2. Product of sides abc = 2400. Formula Used: abc Circumradius R = 4A Solution: R = 2400 4 × 60 2400 R= 240 R = 10 cm. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The mean of a set of 5 numbers is 20. If a number 'p' is added, the mean becomes 22. If another number 'q' replaces 'p', the mean of the original 5 plus 'q' becomes 24. Find p + q.`, o: [`60`, `64`, `76`, `78`], e: `Given: Mean of 5 = 20. p added, Mean = 22. q replaces p, Mean = 24. Formula Used: Sum = Mean × N Solution: Sum(5) = 100. Sum(5+p) = 22 × 6 = 132 p = 32. Sum(5+q) = 24 × 6 = 144 q = 44. p + q = 32 + 44 = 76. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `For a given frequency distribution, if the Mean is 50, the Mode is 44, and the Standard Deviation is 4, find the Karl Pearson's coefficient of skewness.`, o: [`0.5`, `1.5`, `2.0`, `1.2`], e: `Given: Mean = 50, Mode = 44, SD = 4. Formula Used: Coefficient of Skewness = Mean - Mode Standard Deviation Solution: Skewness = 50 - 44 6 4 = 4 = 1.5 Final Answer So the correct answer is (b)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The talented orator (1)/ managed to put out (2)/ his complex ideas (3)/ to the audience with great clarity. (4)`, o: [`(1)`, `(2)`, `(3)`, `(4)`], e: `The correct option is (b). Reason: In part (2), the phrase "put out" is incorrect in the given context. "Put out" generally means "extinguish" (as in a fire), "publish/issue" (put out a notice), or "annoy/inconvenience" (to put someone out). However, the sentence intends to express that the orator explained/expressed/communicated his ideas to the audience clearly. Therefore, the correct phrasal verb should be "put across" or "put forth" or simply "put" (present) his ideas. Correct form of the sentence: "The talented orator managed to put across his complex ideas to the audience with great clarity." Grammatical rule used: Selection of the correct phrasal verb must match the intended meaning and context. "Put across" means "to communicate an idea successfully" whereas "put out" does not conv` },
  { s: `English Language`, q: `What is the one-word substitute for: "The technique of using light and shadow to create depth in visual art"?`, o: [`Chiaroscuro`, `Fresco`, `Mosaic`, `Pointillism`], e: `The correct option is (a). Explanation: The technique of using strong contrasts between light and shadow to give the illusion of volume and depth in painting or drawing is called chiaroscuro. It is especially associated with Renaissance and Baroque art, where light is used dramatically to model forms and create a three- dimensional effect. Meaning: Chiaroscuro means "light-dark" effect; the deliberate arrangement of light and shade to create depth. (Hindi meaning: - ) Example: "The artist used chiaroscuro to make the portrait appear lifelike and three-dimensional." Meanings of the other options: · B: Fresco ­ A painting done on freshly applied wet plaster so that the pigment becomes part of the wall surface. (Hindi meaning: ) · C: Mosaic ­ An art form created by assembling small pieces of ` },
  { s: `English Language`, q: `Choose the most suitable option to replace the highlighted part of the sentence: Rarely, you meet a person so committed to duty.`, o: [`do you meet`, `have you meet`, `you met`, `did you met`], e: `The correct option is (a). Explanation: The sentence begins with the negative/limiting adverb "Rarely". When such an adverb is placed at the beginning of a clause, it triggers inversion (auxiliary verb comes before the subject), similar to question structure. Therefore, "you meet" must change to "do you meet" in the simple present tense. Correct sentence: "Rarely, do you meet a person so committed to duty." Grammatical rule used: Inversion after negative or restrictive adverbs/phrases at the beginning (Rarely, Seldom, Never, Hardly, Scarcely, No sooner, Not only, Little, etc.). Structure: Adverb + Auxiliary + Subject + Main verb. Example: "Never have I seen such honesty." / "Seldom do we find such dedication." Why other options are incorrect: · B: "have you meet" is grammatically wrong bec` },
  { s: `English Language`, q: `Which term refers to "a state in which individuals feel anonymous and therefore act with reduced personal accountability"?`, o: [`Deindividuation`, `Cognitive Dissonance`, `Self-Justification`, `Moral Disengagement`], e: `The correct option is (a). Explanation: Deindividuation refers to a psychological state in which a person's individual identity and self-awareness are reduced, often due to anonymity in a group. Because the individual feels less personally identifiable, personal responsibility and accountability decrease, and the person may engage in impulsive or norm-violating behaviour. Meaning: Deindividuation means loss of personal identity and reduced self-control due to anonymity or group immersion. (Hindi meaning: / ) Example: "In a large crowd, deindividuation may cause some people to behave aggressively because they feel anonymous." Why other options are incorrect: · B: Cognitive Dissonance ­ Mental discomfort caused by holding conflicting beliefs or attitudes. (Hindi meaning: ) · C: Self-Justific` },
  { s: `English Language`, q: `Convert the sentence provided below from its passive voice structure to an active voice structure: The minister's address was being interpreted into several languages by official translators.`, o: [`Official translators had interpreted the minister's address into several languages.`, `Official translators are interpreting the minister's address into several languages.`, `Official translators were interpreting the minister's address into several languages.`, `Official translators interpreted the minister's address into several languages.`], e: `The correct option is (c). Explanation: The passive sentence is in the past continuous passive form: "was being interpreted". To convert to active voice, we bring the agent ("official translators") as the subject and keep the same tense in active form, i.e., past continuous active: "were interpreting". The object "the minister's address" remains the object in active voice, and the rest of the sentence is retained for meaning and clarity. Structure: Passive: Subject (receiver) + was/were being + V3 + by + Agent Active: Agent + was/were + V1-ing + Object Correct active sentence: "Official translators were interpreting the minister's address into several languages." Why other options are incorrect: · A: "had interpreted" is past perfect, which changes the tense and meaning (completed before a` },
  { s: `English Language`, q: `Why other options are incorrect: A: “had interpreted” is past perfect, which changes the tense and meaning (completed before another past action). B: “are interpreting” is present continuous, which changes the time reference. D: “interpreted” is simple past, which removes the ongoing nature of the action indicated by “was being interpreted”. Information booster: Always identify the tense of the passive verb phrase first (was being + V3 indicates past continuous passive). Then apply the equivalent active tense (were + V1-ing). So the correct answer is (c)`, o: [`Benevolent`, `Self-centred`, `Noble`, `Generous`], e: `The correct option is (b). Explanation: The word magnanimous means very generous, kind, and forgiving, especially towards a rival or someone less powerful. It indicates a large-hearted and unselfish attitude. The antonym should therefore express the opposite quality: being concerned mainly with oneself rather than others. Hence, self-centred is the most appropriate antonym. Magnanimous: Showing great generosity of spirit; noble and forgiving, particularly when one is in a position of advantage. (Hindi meaning: / /- ) Example: "Despite the insult, he was magnanimous and forgave his opponent." Self-centred: Focused mainly on one's own needs and interests; lacking concern for others. (Hindi meaning: / ) Example: "A self-centred person rarely considers how their actions affect others." Synonym` },
  { s: `English Language`, q: `A sentence is provided in direct speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding indirect speech. "May I propose a modification to clause three?" the advocate asked courteously.`, o: [`The advocate proposed to modify clause three.`, `The advocate courteously asked may he propose a modification.`, `The advocate courteously inquired whether he might propose a modification to clause three.`, `The advocate advised modifying clause three.`], e: `The correct option is (c). Explanation: The direct speech is an interrogative sentence beginning with "May I...?", which expresses polite permission/request. In indirect speech, such questions are reported using verbs like asked/inquired and the sentence is changed into an affirmative structure with whether/if. Also, "may" generally changes to "might" when the reporting verb is in the past ("asked"). The pronoun "I" changes to "he" because the speaker is "the advocate". The adverb "courteously" is retained appropriately. Correct indirect speech (Option C): "The advocate courteously inquired whether he might propose a modification to clause three." Rules of conversion used: · Interrogative (Yes/No type) changes to statement form using "whether/if". · Modal "may" changes to "might" when repo` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful passage. 1. Sensor units transmitted readings to the monitoring server. 2. A corrective update was deployed to address anomalies. 3. System logs were examined for irregular spikes. 4. Engineers traced the origin of the interference.`, o: [`1-2-3-4`, `3-2-1-4`, `4-2-1-3`, `1-3-4-2`], e: `The correct option is (d). Explanation: A meaningful and logical sequence should show the flow: data is received, then problem evidence is checked, then the cause is traced, and finally a corrective step is taken. Sentence (1) naturally introduces the process: sensors send readings to the server. After readings are received, engineers check evidence in the system, so (3) follows: logs are examined for irregular spikes. Once anomalies are confirmed through logs, the next step is investigation, so (4) follows: engineers traced the origin of the interference. After identifying the cause, a solution is implemented, so (2) comes last: a corrective update was deployed. Correct order: 1 3 4 2 Why this order is correct (exam-style points): · (1) sets the context by describing the initial system ac` },
  { s: `English Language`, q: `(3) logically follows because logs are examined after data is received to detect irregularities. (4) comes next as the investigative action taken after detecting spikes/anomalies. (2) is the concluding remedial action, which is typically deployed after diagnosis. Information booster: In para-jumble questions, identify a clear starting sentence (context/trigger) and a clear ending sentence (solution/result). Here, (1) is the trigger and (2) is the final corrective result. So the correct answer is (d)`, o: [`Dormant`, `Noisy`, `Boisterous`, `Turbulent`], e: `The correct option is (a). Explanation: The word quiescent means inactive, quiet, or at rest; it often refers to something that is temporarily not active but can become active again. The closest synonym among the options is dormant, which also means inactive or in a state of rest, especially for a period. Quiescent: In a state of inactivity or repose; quiet and not active at the moment. (Hindi meaning: //) Example: "The volcano has been quiescent for decades, but scientists still monitor it." Dormant: Temporarily inactive, asleep, or not developing, but capable of becoming active. (Hindi meaning: /) Example: "Some seeds remain dormant until conditions become favourable." Synonyms (of quiescent): inactive, dormant, latent, still. Antonyms (of quiescent): active, turbulent, restless, vigorou` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The CEO emphasized that (1)/ the new recruits (2)/ must demonstrate (3)/ punctuality, dedication, and be creative. (4)/`, o: [`(1)`, `(2)`, `(3)`, `(4)`], e: `The correct option is (d). Explanation: The error lies in part (4): "punctuality, dedication, and be creative." The list is not parallel. "Punctuality" and "dedication" are nouns, but "be creative" is a verb phrase. In a series, items should follow parallel structure (same grammatical form). Therefore, it should be "punctuality, dedication, and creativity" (all nouns) or "must be punctual, (be) dedicated, and (be) creative" (all adjective complements/verb phrases). Correct sentence (one acceptable correction): "The CEO emphasized that the new recruits must demonstrate punctuality, dedication, and creativity." Grammatical rule used: Parallelism in coordination. When elements are joined by "and/or", they should be in the same grammatical form (noun + noun + noun, or verb + verb + verb, etc.)` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful passage. 1. The final report is submitted to the international review body for ratification. 2. Stakeholders then examine drafts and recommend corrections. 3. After incorporating inputs, a final version is compiled. 4. In the beginning, national consultations produce region-specific findings.`, o: [`1-3-2-4`, `4-2-3-1`, `2-4-3-1`, `3-1-2-4`], e: `The correct option is (b). Explanation: The passage describes a formal report-making process from initial consultations to final submission. Sentence (4) clearly signals the beginning: "In the beginning, national consultations produce region-specific findings." After initial findings, draft documents are prepared and reviewed, so (2) logically follows: stakeholders examine drafts and suggest corrections. Once inputs/corrections are incorporated, the final version is prepared, so (3) follows. Finally, the completed report is submitted for ratification, so (1) comes at the end. Correct order: 4 2 3 1 Why this order is correct (exam-style points): · (4) begins with a clear time marker "In the beginning", making it the natural opening. · (2) uses "then", indicating the next stage after drafts/` },
  { s: `English Language`, q: `Choose the correct meaning of idiom given below: "Know which way the wind blows"`, o: [`Remain undecided in every matter`, `Understand the prevailing trend or public mood`, `Seek constant approval from others`, `Avoid all risks`], e: `The correct option is (b). Explanation: The idiom "know which way the wind blows" means to understand the current situation, the likely outcome, or the prevailing trend-- especially public opinion or power dynamics--so that one can act accordingly. It refers to being aware of "which side is gaining strength" or "what people generally think" before taking a decision. Meaning of the idiom: To be aware of the prevailing circumstances or public mood; to understand the direction of events. (Hindi idiom meaning: ) Example: "Before supporting any policy, the leader tried to know which way the wind blows in the public." Other related idioms and meanings: · "Test the waters" ­ To try something cautiously before making a full commitment. · "Read the room" ­ To understand the mood or reactions of peo` },
  { s: `English Language`, q: `Identify the grammatical role of "whereby" in the clause: "...secret conference, whereby reckless slanders were sown..." Read the passage and answer the questions: It is with the utmost seriousness that we convey tidings from the Continent, where the designs of foreign Powers signal a disturbance most grievous to the peace of Europe. Communications received in our office--though some arrive through channels of uncertain credibility--suggest that several Ministers of State, long discontented, have entered into secret conference, whereby reckless slanders were sown and the fragile Peace lately concluded at Amiens is placed in jeopardy. The people, eager for repose after years of convulsion, remain restless; their fears are inflamed by pamphleteers whose incendiary harangues find ready acceptance among the credulous. Meanwhile, at Westminster, the Commons are immersed in heated deliberation on whether naval preparations ought to be increased, lest hostile stratagems leave our coasts exposed. An official appeal has been issued urging the citizenry to remain vigilant yet orderly, for vigilance--tempered by prudence--is held by many learned gentlemen to be the surest barrier against perfidious ambition. Further dispatches are awaited with no little apprehension.`, o: [`Preposition`, `Conjunction`, `Relative Adverb`, `Pronoun`], e: `The correct option is (c). Explanation: The word whereby means "by which" or "through which," and it introduces a clause explaining the method or means by which something happens. In the phrase "secret conference, whereby reckless slanders were sown," it connects the noun "conference" to the result/action that followed, indicating the means or process. Hence, it functions as a relative adverb (a connector introducing a relative clause with the sense of "by which"). How it works grammatically: Relative adverbs (where, when, why, whereby) introduce clauses and relate them to an earlier noun/idea, providing additional information. Why other options are incorrect: · A: Preposition is a word used before a noun/pronoun (in, on, by). "Whereby" is not functioning as a simple preposition here. · B:` },
  { s: `English Language`, q: `What is the closest meaning of "grievous" as used in the passage? Read the passage and answer the questions: It is with the utmost seriousness that we convey tidings from the Continent, where the designs of foreign Powers signal a disturbance most grievous to the peace of Europe. Communications received in our office--though some arrive through channels of uncertain credibility--suggest that several Ministers of State, long discontented, have entered into secret conference, whereby reckless slanders were sown and the fragile Peace lately concluded at Amiens is placed in jeopardy. The people, eager for repose after years of convulsion, remain restless; their fears are inflamed by pamphleteers whose incendiary harangues find ready acceptance among the credulous. Meanwhile, at Westminster, the Commons are immersed in heated deliberation on whether naval preparations ought to be increased, lest hostile stratagems leave our coasts exposed. An official appeal has been issued urging the citizenry to remain vigilant yet orderly, for vigilance--tempered by prudence--is held by many learned gentlemen to be the surest barrier against perfidious ambition. Further dispatches are awaited with no little apprehension.`, o: [`Routine`, `Severe and painful`, `Hidden`, `Insignificant`], e: `The correct option is (b). Explanation: The word grievous in the passage appears in the phrase "a disturbance most grievous to the peace of Europe." Here, it describes something that causes serious harm, pain, or suffering to peace. Thus, the closest meaning is "severe and painful," i.e., extremely serious and damaging. Context clue: The passage uses strong words like "disturbance," "jeopardy," and "apprehension," which support the sense of seriousness and harm. Why other options are incorrect: · A: Routine means ordinary and common; it contradicts the serious tone of the passage. · C: Hidden means concealed; it does not match the sense of severity or painful impact. · D: Insignificant means unimportant; the passage clearly treats the disturbance as highly serious. So the correct answer is` },
  { s: `English Language`, q: `The word "slanders" most nearly means: Read the passage and answer the questions: It is with the utmost seriousness that we convey tidings from the Continent, where the designs of foreign Powers signal a disturbance most grievous to the peace of Europe. Communications received in our office--though some arrive through channels of uncertain credibility--suggest that several Ministers of State, long discontented, have entered into secret conference, whereby reckless slanders were sown and the fragile Peace lately concluded at Amiens is placed in jeopardy. The people, eager for repose after years of convulsion, remain restless; their fears are inflamed by pamphleteers whose incendiary harangues find ready acceptance among the credulous. Meanwhile, at Westminster, the Commons are immersed in heated deliberation on whether naval preparations ought to be increased, lest hostile stratagems leave our coasts exposed. An official appeal has been issued urging the citizenry to remain vigilant yet orderly, for vigilance--tempered by prudence--is held by many learned gentlemen to be the surest barrier against perfidious ambition. Further dispatches are awaited with no little apprehension.`, o: [`Truthful remarks`, `Festive announcements`, `Malicious false statements`, `Formal directives`], e: `The correct option is (c). Explanation: In the passage, "reckless slanders were sown" suggests that false and damaging statements were spread secretly to create unrest and place peace "in jeopardy". The word slanders refers to statements that harm someone's reputation, usually by being false and malicious. Hence, the closest meaning is "malicious false statements". Context clue: The phrase "reckless slanders" is linked to secret conferences and threats to peace, showing that the statements were intended to mislead and provoke. Why other options are incorrect: · A: "Truthful remarks" is the opposite of slander, because slander is based on falsehood. · B: "Festive announcements" is unrelated to the serious and alarming tone of the passage. · D: "Formal directives" refers to official orders, ` },
  { s: `English Language`, q: `According to the passage, what is the chief aim of the official "appeal" to the citizenry? Read the passage and answer the questions: It is with the utmost seriousness that we convey tidings from the Continent, where the designs of foreign Powers signal a disturbance most grievous to the peace of Europe. Communications received in our office--though some arrive through channels of uncertain credibility--suggest that several Ministers of State, long discontented, have entered into secret conference, whereby reckless slanders were sown and the fragile Peace lately concluded at Amiens is placed in jeopardy. The people, eager for repose after years of convulsion, remain restless; their fears are inflamed by pamphleteers whose incendiary harangues find ready acceptance among the credulous. Meanwhile, at Westminster, the Commons are immersed in heated deliberation on whether naval preparations ought to be increased, lest hostile stratagems leave our coasts exposed. An official appeal has been issued urging the citizenry to remain vigilant yet orderly, for vigilance--tempered by prudence--is held by many learned gentlemen to be the surest barrier against perfidious ambition. Further dispatches are awaited with no little apprehension.`, o: [`To promote public festivities`, `To boost commerce`, `To caution against hostile influence while preserving order`, `To declare a new administration`], e: `The correct option is (c). Explanation: The passage states: "An official appeal has been issued urging the citizenry to remain vigilant yet orderly." This indicates a dual purpose: (1) to warn people about possible hostile designs and threats, and (2) to ensure public conduct remains disciplined and calm rather than disorderly. The government wants citizens to be alert (vigilant) but alsCoopmyariignthatin©p2e0a2c6e A(odrddae2rl4y7). Therefore, the chief aim is to caution against hostile influence while preserving order. Context from the passage: The writer highlights danger from foreign powers and internal unrest caused by pamphleteers. Hence, the appeal emphasizes vigilance "tempered by prudence" so that the nation remains protected without falling into panic or chaos. Why other options a` },
  { s: `English Language`, q: `. In the sentence "...lest hostile stratagems leave our coasts exposed," the word "stratagems" is a: Read the passage and answer the questions: It is with the utmost seriousness that we convey tidings from the Continent, where the designs of foreign Powers signal a disturbance most grievous to the peace of Europe. Communications received in our office--though some arrive through channels of uncertain credibility--suggest that several Ministers of State, long discontented, have entered into secret conference, whereby reckless slanders were sown and the fragile Peace lately concluded at Amiens is placed in jeopardy. The people, eager for repose after years of convulsion, remain restless; their fears are inflamed by pamphleteers whose incendiary harangues find ready acceptance among the credulous. Meanwhile, at Westminster, the Commons are immersed in heated deliberation on whether naval preparations ought to be increased, lest hostile stratagems leave our coasts exposed. An official appeal has been issued urging the citizenry to remain vigilant yet orderly, for vigilance--tempered by prudence--is held by many learned gentlemen to be the surest barrier against perfidious ambition. Further dispatches are awaited with no little apprehension.`, o: [`Adjective`, `Noun`, `Adverb`, `Verb`], e: `The correct option is (b). Explanation: In the clause "lest hostile stratagems leave our coasts exposed," the word stratagems refers to "plans" or "schemes" used by hostile forces. Such a word names a thing/idea, so it functions as a noun. It is also the subject of the verb "leave" in that clause ("stratagems leave our coasts exposed"). How to identify: A noun names a person, place, thing, or idea. "Stratagems" names tactical schemes (an idea/plan), therefore it is a noun. Why other options are incorrect: · A: Adjective describes a noun; "stratagems" is itself the naming word, not a describing word. · C: Adverb modifies a verb/adjective/adverb; "stratagems" does not modify anything. · D: Verb denotes an action; "stratagems" is not an action, it is the plan itself. So the correct answer is ` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate option: By the time the medical team arrived, the residents __ to safer ground.`, o: [`have moved`, `had moved`, `moved`, `would move`], e: `The correct option is (b). Explanation: The sentence uses the time expression "By the time the medical team arrived," which indicates that one action (residents moving) was completed before another action in the past (medical team arrived). For an action completed before a point in the past, we use the past perfect tense. Therefore, "had moved" is correct. Correct sentence: "By the time the medical team arrived, the residents had moved to safer ground." Hindi meaning of the key idea: "had moved" indicates an earlier completed past action. (Hindi meaning: ) Example: "By the time the train reached the station, we had already left." Why other options are incorrect: · A: "have moved" is present perfect and does not fit with the past-time clause "arrived". · C: "moved" (simple past) can sometim` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful sentence: P. among industry stakeholders for review Q. to obtain structured feedback before approval R. the draft compliance guidelines S. prepared by the inter-ministerial committee`, o: [`RQSP`, `PQRS`, `QRSP`, `RSQP`], e: `The correct option is (d). Explanation: The core noun phrase is "the draft compliance guidelines" (R). This must be modified by "prepared by the inter-ministerial committee" (S), which clearly describes the guidelines. After forming this complete subject phrase (R + S), we need the purpose clause "to obtain structured feedback before approval" (Q), which explains why the guidelines are circulated. Finally, "among industry stakeholders for review" (P) logically completes the idea by stating where/among whom the guidelines are circulated for review. Correct arrangement: R S Q P Meaningful sentence formed: "The draft compliance guidelines prepared by the inter-ministerial committee to obtain structured feedback before approval among industry stakeholders for review." Exam-style note: In such ` },
  { s: `English Language`, q: `Convert the sentence provided below from its passive voice structure to an active voice structure: This editorial is going to be published by the journal.`, o: [`The journal will publish this editorial.`, `The journal is going to publish this editorial.`, `The journal publishes this editorial.`, `The journal had published this editorial.`], e: `The correct option is (b). Explanation: The passive sentence uses the structure "is going to be published," which indicates a planned future action (near future intention). In active voice, we bring the agent "the journal" as the subject and keep the same "going to" future intention: "is going to publish." The object "this editorial" becomes the object in active voice. Structure: Passive: Object + is/are going to be + V3 + by + Agent Active: Agent + is/are going to + V1 + Object Correct active sentence: "The journal is going to publish this editorial." Why other options are incorrect: · A: "will publish" changes the exact intended sense from "Cgoopinygrigtoh"t (©pla2n0n2e6dA) dtoda"2w4il7l" (simple future), which is not the closest structural match. · C: "publishes" is simple present, chan` },
  { s: `English Language`, q: `Change the following from active to passive: The reviewers would have amended the draft if fresh evidence had been presented.`, o: [`The draft would have been amended by the reviewers if fresh evidence had been presented.`, `The draft would amend by the reviewers if fresh evidence had been presented.`, `The draft could be amended by the reviewers if fresh evidence had been presented.`, `The draft was amended by the reviewers if fresh evidence had been presented.`], e: `The correct option is (a). Explanation: The active sentence uses a conditional with "would have amended," which is the perfect conditional (would have + V3). To convert to passive, the object "the draft" becomes the subject, and the verb changes to "would have been amended" (would have been + V3). The agent "the reviewers" is added with "by". The if-clause "if fresh evidence had been presented" remains unchanged because it already describes a past perfect condition. Structure: Active: Subject + would have + V3 + Object Passive: Object + would have been + V3 + by + Subject Correct passive sentence: "The draft would have been amended by the reviewers if fresh evidence had been presented." Why other options are incorrect: · B: "would amend" is incorrect in form and missing "been"; also "amend` },
  { s: `English Language`, q: `Which word has a spelling mistake?`, o: [`Convalescence`, `Obsequious`, `Conflageration`, `Reticent`], e: `The correct option is (c). Explanation: Option (C) "Conflageration" is incorrectly spelt. The correct spelling is conflagration, which means a large destructive fire; it can also refer to a major conflict. (Hindi meaning: / ) Example: "The conflagration spread rapidly due to strong winds." Part of speech: "Conflagration" is a noun (it names an event/state of a great fire). Meanings of all the given options: · A: Convalescence ­ The period of recovery after illness or medical treatment. (Hindi meaning: -/- ) · B: Obsequious ­ Excessively obedient or flattering for personal advantage. (Hindi meaning: / ) · C: Conflagration (correct form) ­ A large destructive fire; an intense conflict. (Hindi meaning: ) · D: Reticent ­ Not revealing one's thoughts or feelings readily; reserved. (Hindi meanin` },
  { s: `English Language`, q: `A sentence is provided in indirect speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding direct speech. The analyst remarked that the report, although comprehensive, was inconsistent in its interpretation of data.`, o: [`"The report is comprehensive, but your interpretation is inconsistent," the analyst remarked.`, `"Though the report is comprehensive, the interpretation of the data is not consistent," said the analyst.`, `"It's comprehensive, but the data interpretation is inconsistent," the analyst said.`, `"Your interpretation is inconsistent even though the report is comprehensive," said the analyst.`], e: `The correct option is (b). Explanation: The indirect speech states a past remark: "the report ... was inconsistent." When converting to direct speech, we should present the exact content of the remark with appropriate connectors and a reporting clause. Option (B) accurately reflects the concessive idea "although comprehensive" using "though" and keeps the focus on "the interpretation of the data" being "not consistent," which matches "was inconsistent in its interpretation of data." It also uses a correct reporting structure: quotation + reporting verb. Rules of conversion used: · Indirect statement becomes a direct quotation with quotation marks. · Concessive connector "although" can be expressed as "though/even though" in direct speech while retaining meaning. · The reporting verb "remar` },
  { s: `English Language`, q: `Why other options are incorrect: A: Introduces “your interpretation,” which is not stated in the original; the original refers to the report’s interpretation of data, not necessarily addressing “you.” C: Uses informal contraction “It’s” and compresses the statement; it is less precise and less formal for exam-standard direct speech. D: Again introduces “your interpretation,” shifting the meaning and the target of criticism away from the report. Information booster: In speech conversion questions, avoid options that add new pronouns (you/your) unless clearly implied by the original sentence. Meaning must remain faithful. So the correct answer is (b)`, o: [`Recalcitrant`, `Recalserant`, `Recalcittrent`, `Ricalcetrant`], e: `The correct option is (a). Explanation: The correctly spelled word is recalcitrant. It means stubbornly resistant to authority or control; unwilling to obey rules or discipline. (Hindi meaning: // ) Example: "The recalcitrant employee refused to follow the company's safety instructions." Meanings of the other options: · B: Recalserant ­ Not a correct English word; incorrect spelling. (Hindi meaning: ) · C: Recalcittrent ­ Not a correct English word; incorrect spelling. (Hindi meaning: ) · D: Ricalcetrant ­ Not a correct English word; incorrect spelling. (Hindi meaning: ) Information booster: "Recalcitrant" is often confused in spelling due to multiple consonants. Remember the pattern: re + calcitrant (contains "calcitr"). So the correct answer is (a)` },
  { s: `English Language`, q: `Choose the correctly spelt word that means \`excessively talkative, especially about trivial matters'.`, o: [`Garrulous`, `Garrolous`, `Garruless`, `Garralouse`], e: `The correct option is (a). Explanation: The correctly spelt word is garrulous. It means excessively talkative, often about unimportant or trivial matters, and difficult to stop once started. (Hindi meaning: / ) Example: "The garrulous neighbour kept talking for an hour about minor incidents." Meanings of the other options: · B: Garrolous ­ Incorrect spelling; not a standard English word. (Hindi meaning: ) · C: Garruless ­ Incorrect spelling; not the correct form. (Hindi meaning: ) · D: Garralouse ­ Incorrect spelling; not a standard English word. (Hindi meaning: ) Information booster: "Garrulous" is often tested with similar-looking spellings. Remember it has double "r" and ends with "-ous". So the correct answer is (a)` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Graduate Level)',
      code: 'SSC-SSP',
      description: 'Staff Selection Commission - Selection Post (Graduate Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Graduate Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Graduation) - 2 August 2025 Shift-3 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Graduate', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '3',
    pyqExamName: 'SSC Selection Post Phase XIII (Graduate) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
